    const visited = new Set<number>();
    const mustGraph = new Map<number, number[]>();

    for (const [u, v, s] of mustEdges) {
        if (!mustGraph.has(u)) mustGraph.set(u, []);
        if (!mustGraph.has(v)) mustGraph.set(v, []);
        mustGraph.get(u)!.push(v);
        mustGraph.get(v)!.push(u);
